    private function t(string $key): string
    {
        $value = $this->translations[$this->adminLang][$key] ?? $this->translations['en'][$key] ?? $key;
        return $this->normalizeText((string) $value);
    }

    private function normalizeText(string $value): string
    {
        $text = $value;
        for ($i = 0; $i < 2; $i++) {
            if (!preg_match('/ГѓЖ’|ГѓвЂљ|ГѓВў/u', $text)) {
                break;
            }

            if (function_exists('mb_convert_encoding')) {
                $converted = @mb_convert_encoding($text, 'UTF-8', 'Windows-1252');
            } else {
                $converted = @iconv('Windows-1252', 'UTF-8//IGNORE', $text);
            }

            if (!is_string($converted) || $converted === '') {
                break;
            }

            $text = $converted;
        }

        return $text;
    }
    
    public function handle(): void
    {
        if (session_status() === PHP_SESSION_NONE) {
            session_start();
        }
        
        // Handle language switching
        if (isset($_GET['lang']) && in_array($_GET['lang'], ['sv', 'en'])) {
            $_SESSION['admin_lang'] = $_GET['lang'];
            $this->adminLang = $_GET['lang'];
        } elseif (isset($_SESSION['admin_lang'])) {
            $this->adminLang = $_SESSION['admin_lang'];
        }
        
        $action = $_GET['action'] ?? 'login';
        
        if ($action === 'logout') {
            Logger::audit('admin.logout', $this->auditContext([
                'username' => (string) ($_SESSION['admin_username'] ?? 'unknown'),
            ]));
            $_SESSION = [];
            session_regenerate_id(true);
            header('Location: /admin.php');
            exit;
        }

        if ($action === 'reset_password') {
