    private function cacheTableColumns(): void
    {
        $conn = Database::connection();
        $result = $conn->query("SHOW COLUMNS FROM grundteam_applications");
        while ($row = $result->fetch_assoc()) {
            $this->tableColumns[] = $row['Field'];
        }
    }
    
    private function hasColumn(string $column): bool
    {
        return in_array($column, $this->tableColumns);
    }
    
    private function getOrderByColumn(): string
    {
        if ($this->hasColumn('created_at')) {
            return 'created_at';
        } elseif ($this->hasColumn('id')) {
            return 'id';
        }
        return 'id';
    }
    
    private function showError(string $message): void
    {
        echo '<!DOCTYPE html><html lang="sv"><head><meta charset="UTF-8"><title>Fel</title>';
        echo '<style>body{font-family:sans-serif;max-width:600px;margin:100px auto;padding:20px;}';
        echo '.error{background:#fee;border:2px solid #c00;padding:20px;border-radius:8px;}</style></head><body>';
        echo '<div class="error"><h2>Fel</h2><p>' . htmlspecialchars($this->normalizeText($message), ENT_QUOTES, 'UTF-8') . '</p>';
        echo '<p><a href="/admin.php?action=dashboard">Tillbaka till dashboard</a></p></div></body></html>';
    }
    
