        $resetOk = isset($_GET['reset']) && $_GET['reset'] === '1';
        $errorMessage = $error;
        include resource_path('views/admin-login-clean.php');
    }
private function showResetPasswordForm(?string $error): void
    {
        $csrfToken = csrf_token();
        $errorMessage = $error;
        include resource_path('views/admin-reset-clean.php');
    }
private function showDashboard(): void
    {
        $conn = Database::connection();
        
        $filterType = $_GET['filter_type'] ?? 'all';
        $filterRegion = $_GET['filter_region'] ?? 'all';
        $search = $_GET['search'] ?? '';
        
        $where = [];
        $params = [];
        $types = '';
        
        if ($filterType !== 'all') {
            $where[] = 'application_type = ?';
            $params[] = $filterType;
            $types .= 's';
        }
        
        if ($filterRegion !== 'all') {
            $where[] = 'region = ?';
            $params[] = $filterRegion;
            $types .= 's';
        }
        
        if ($search !== '') {
            $where[] = "(name LIKE ? OR email LIKE ? OR COALESCE(org_name, '') LIKE ?)";
            $searchParam = '%' . $search . '%';
            $params[] = $searchParam;
            $params[] = $searchParam;
            $params[] = $searchParam;
            $types .= 'sss';
        }
        
        $whereClause = count($where) > 0 ? 'WHERE ' . implode(' AND ', $where) : '';
        $orderBy = $this->getOrderByColumn();
        
        $query = "SELECT * FROM grundteam_applications {$whereClause} ORDER BY {$orderBy} DESC";
        
        $result = null;
        if (count($params) > 0) {
            $stmt = $conn->prepare($query);
            if ($stmt) {
                $stmt->bind_param($types, ...$params);
                $stmt->execute();
                $result = $stmt->get_result();
                $stmt->close();
            }
        } else {
            $result = $conn->query($query);
        }
        
        $applications = [];
        if ($result instanceof \mysqli_result) {
            while ($row = $result->fetch_assoc()) {
                $applications[] = $row;
            }
        }
        
        $stats = [
            'total' => $this->queryCount($conn, 'SELECT COUNT(*) as c FROM grundteam_applications'),
            'individual' => $this->queryCount($conn, "SELECT COUNT(*) as c FROM grundteam_applications WHERE application_type='individual'"),
            'group' => $this->queryCount($conn, "SELECT COUNT(*) as c FROM grundteam_applications WHERE application_type='group'"),
        ];
        
        if ($this->hasColumn('created_at')) {
            $stats['today'] = $this->queryCount($conn, 'SELECT COUNT(*) as c FROM grundteam_applications WHERE DATE(created_at) = CURDATE()');
        }
        
        ob_start();
        include __DIR__ . '/../../../resources/views/admin-dashboard.php';
        $html = (string) ob_get_clean();
        echo $this->normalizeText($html);
    }

    private function queryCount(\mysqli $conn, string $sql): int
    {
        $result = $conn->query($sql);
        if (!$result instanceof \mysqli_result) {
            return 0;
        }

        $row = $result->fetch_assoc();
        return (int) ($row['c'] ?? 0);
    }
    
    private function viewApplication(): void
    {
        $id = (int) ($_GET['id'] ?? 0);
        
        if ($id <= 0) {
            header('Location: /admin.php?action=dashboard');
            exit;
        }
        
        $conn = Database::connection();
        $stmt = $conn->prepare('SELECT * FROM grundteam_applications WHERE id = ?');
        $stmt->bind_param('i', $id);
        $stmt->execute();
        $result = $stmt->get_result();
        $application = $result->fetch_assoc();
        
        if (!$application) {
            header('Location: /admin.php?action=dashboard');
            exit;
        }

        Logger::audit('admin.application.view', $this->auditContext([
            'application_id' => $id,
        ]));
        
        include __DIR__ . '/../../../resources/views/admin-view.php';
    }
    
    private function replyToApplication(): void
    {
        $id = (int) ($_GET['id'] ?? 0);
        
        if ($id <= 0) {
            header('Location: /admin.php?action=dashboard');
            exit;
        }
        
        $conn = Database::connection();
