    private function deleteApplication(): void
    {
        $id = (int) ($_GET['id'] ?? 0);
        
        if ($id <= 0) {
            header('Location: /admin.php?action=dashboard');
            exit;
        }
        
        if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['confirm'])) {
            if (!verify_csrf_token($_POST['_token'] ?? null)) {
                header('Location: /admin.php?action=view&id=' . $id . '&error=csrf');
                exit;
            }

            $conn = Database::connection();
            $stmt = $conn->prepare('DELETE FROM grundteam_applications WHERE id = ?');
            $stmt->bind_param('i', $id);
            $stmt->execute();
            Logger::audit('admin.application.delete', $this->auditContext([
                'application_id' => $id,
            ]));
            
            header('Location: /admin.php?action=dashboard&deleted=1');
            exit;
        }
        
        header('Location: /admin.php?action=dashboard');
        exit;
    }
    
    private function exportApplications(): void
    {
        $conn = Database::connection();
        $result = $conn->query('SELECT * FROM grundteam_applications ORDER BY id DESC');
        
        header('Content-Type: text/csv; charset=utf-8');
        header('Content-Disposition: attachment; filename="ansokningar_' . date('Y-m-d') . '.csv"');
        Logger::audit('admin.export.csv', $this->auditContext());
        
        $out = fopen('php://output', 'w');
        fprintf($out, chr(0xEF).chr(0xBB).chr(0xBF));
        
        fputcsv($out, ['ID', 'Typ', 'Namn', 'Email', 'Region', 'Bidrag', 'Org Namn', 'Org Bidrag', 'Org Motiv', 'GDPR', 'Datum']);
        
        while ($row = $result->fetch_assoc()) {
            fputcsv($out, [
                $row['id'],
                $row['application_type'],
                $row['name'],
                $row['email'],
                $row['region'],
                $row['individual_contribution'] ?? '',
                $row['org_name'] ?? '',
                $row['org_contribution'] ?? '',
                $row['org_motive'] ?? '',
                $row['gdpr_consent'] ? 'Ja' : 'Nej',
                $row['created_at'] ?? $row['id']
            ]);
        }
        
        fclose($out);
        exit;
    }
    
    private function updateStatus(): void
    {
        if (!$this->hasColumn('status')) {
            header('Location: /admin.php?action=dashboard');
            exit;
        }

        if ($_SERVER['REQUEST_METHOD'] !== 'POST' || !verify_csrf_token($_POST['_token'] ?? null)) {
            header('Location: /admin.php?action=dashboard');
            exit;
        }
        
        $id = (int) ($_GET['id'] ?? 0);
        $status = $_POST['status'] ?? '';
        
        if ($id > 0 && in_array($status, ['new', 'reviewed', 'replied', 'accepted', 'rejected'])) {
            $conn = Database::connection();
            $stmt = $conn->prepare('UPDATE grundteam_applications SET status = ? WHERE id = ?');
            $stmt->bind_param('si', $status, $id);
            $stmt->execute();
            Logger::audit('admin.application.status_update', $this->auditContext([
                'application_id' => $id,
                'status' => $status,
            ]));
        }
        
        header('Location: /admin.php?action=view&id=' . $id);
        exit;
    }

    private function verifyCredentials(string $username, string $password, string $totpCode = '', string $method = 'password'): bool
    {
        $method = strtolower(trim($method));
        if ($username === '' || !in_array($method, ['password', 'totp'], true)) {
            return false;
        }

        $mode = strtolower((string) env('ADMIN_AUTH_MODE', 'env'));

        if ($mode === 'database' || $mode === 'db') {
            return $this->verifyDatabaseLogin($username, $password, $totpCode, $method);
        }

        if ($mode === 'hybrid') {
            if ($this->verifyDatabaseLogin($username, $password, $totpCode, $method)) {
                return true;
            }

            if ($method === 'totp' && $this->verifySharedTotpLogin($username, $totpCode)) {
                return true;
            }

            if ($method === 'password') {
                return $this->verifyEnvCredentials($username, $password);
            }

            return false;
        }

        if ($method === 'totp') {
            return $this->verifySharedTotpLogin($username, $totpCode);
        }

        return $this->verifyEnvCredentials($username, $password);
    }

    private function verifyEnvCredentials(string $username, string $password): bool
    {
        if ($username === '' || $password === '') {
            return false;
        }

        $expectedUsername = trim((string) env('ADMIN_USERNAME', 'admin'));
        if ($expectedUsername === '') {
            $expectedUsername = 'admin';
        }

        if (!hash_equals($expectedUsername, $username)) {
            return false;
        }

        $passwordHash = trim((string) env('ADMIN_PASSWORD_HASH', ''));
        if ($passwordHash === '') {
            Logger::error('Admin login failed: ADMIN_PASSWORD_HASH missing');
            return false;
        }

        return $this->verifyPbkdf2Password($password, $passwordHash);
    }

    private function verifyDatabaseLogin(string $username, string $password, string $totpCode, string $method): bool
    {
        $conn = $this->getDatabaseConnection();
        if (!$conn instanceof \mysqli) {
            return $method === 'totp' && $this->verifySharedTotpLogin($username, $totpCode);
        }

        $table = $this->adminUsersTable();
        $admin = $this->fetchAdminUser($conn, $table, $username);
        if (!is_array($admin)) {
            return $method === 'totp' && $this->verifySharedTotpLogin($username, $totpCode);
        }

        if ($this->isDbAccountLocked($admin)) {
            return false;
        }

        $ok = false;

        if ($method === 'password') {
            $hash = (string) ($admin['password_hash'] ?? '');
            $ok = $hash !== '' && password_verify($password, $hash);
        }

        if ($method === 'totp') {
            $secret = (string) ($admin['totp_secret'] ?? '');
            $enabled = (int) ($admin['totp_enabled'] ?? 0) === 1;
            $ok = ($enabled && $secret !== '' && $this->verifyTotpCode($secret, $totpCode))
                || $this->verifySharedTotpLogin($username, $totpCode);
        }

        if (!$ok) {
            $this->recordDatabaseFailedAttempt($conn, $table, $username, (int) ($admin['failed_attempts'] ?? 0));
            return false;
        }

        $this->recordDatabaseSuccessfulLogin($conn, $table, $username);
        return true;
    }

    private function resetDatabasePasswordByTotp(string $username, string $totpCode, string $newPassword): bool
    {
        $conn = $this->getDatabaseConnection();
        if (!$conn instanceof \mysqli) {
            return false;
        }

        $table = $this->adminUsersTable();
        $admin = $this->fetchAdminUser($conn, $table, $username);
        if (!is_array($admin)) {
            return false;
        }

        $enabled = (int) ($admin['totp_enabled'] ?? 0) === 1;
        $secret = (string) ($admin['totp_secret'] ?? '');
        if (!$enabled || $secret === '' || !$this->verifyTotpCode($secret, $totpCode)) {
            return false;
        }

        $passwordHash = password_hash($newPassword, PASSWORD_BCRYPT);
        if (!is_string($passwordHash) || $passwordHash === '') {
            return false;
        }

        $stmt = $conn->prepare(
            "UPDATE `{$table}`
             SET password_hash = ?, failed_attempts = 0, locked_until = NULL, password_changed_at = NOW(), updated_at = NOW()
             WHERE username = ?"
        );

        if (!$stmt) {
            return false;
        }

        $stmt->bind_param('ss', $passwordHash, $username);
        $ok = $stmt->execute();
        $stmt->close();

        return $ok;
    }

    private function verifySharedTotpLogin(string $username, string $totpCode): bool
    {
        if (!$this->isSharedTotpUser($username)) {
            return false;
        }

        $secret = trim((string) env('ADMIN_TOTP_SECRET', ''));
        if ($secret === '') {
            return false;
        }

        return $this->verifyTotpCode($secret, $totpCode);
    }

    private function isSharedTotpUser(string $username): bool
    {
        $raw = (string) env('ADMIN_TOTP_USERNAMES', 'admin,ceoadmin');
        $items = array_filter(array_map('trim', explode(',', strtolower($raw))));
        if ($items === []) {
            return false;
        }

        return in_array(strtolower($username), $items, true);
    }

    private function getDatabaseConnection(): ?\mysqli
    {
        try {
            return Database::connection();
        } catch (\Throwable) {
            return null;
        }
    }

    private function adminUsersTable(): string
    {
        return preg_replace('/[^a-zA-Z0-9_]/', '', (string) env('ADMIN_USERS_TABLE', 'admin_users')) ?: 'admin_users';
    }

    private function fetchAdminUser(\mysqli $conn, string $table, string $username): ?array
    {
        $sql = "SELECT id, username, password_hash, totp_secret, totp_enabled, failed_attempts, locked_until
                FROM `{$table}`
                WHERE username = ?
                LIMIT 1";

        $stmt = $conn->prepare($sql);
        if (!$stmt) {
            return null;
        }

        $stmt->bind_param('s', $username);
        $stmt->execute();
        $result = $stmt->get_result();
        $admin = $result ? $result->fetch_assoc() : null;
        $stmt->close();

        return is_array($admin) ? $admin : null;
    }

    private function isDbAccountLocked(array $admin): bool
    {
        $lockedUntil = $admin['locked_until'] ?? null;
        return is_string($lockedUntil) && $lockedUntil !== '' && strtotime($lockedUntil) > time();
    }

    private function recordDatabaseFailedAttempt(\mysqli $conn, string $table, string $username, int $currentAttempts): void
    {
        $attempts = $currentAttempts + 1;
        $lockUntil = $attempts >= self::LOGIN_MAX_ATTEMPTS
            ? date('Y-m-d H:i:s', time() + self::LOGIN_WINDOW_SECONDS)
            : null;

        if ($lockUntil !== null) {
            $stmt = $conn->prepare(
                "UPDATE `{$table}`
                 SET failed_attempts = ?, locked_until = ?, updated_at = NOW()
                 WHERE username = ?"
            );
            if (!$stmt) {
                return;
            }
            $stmt->bind_param('iss', $attempts, $lockUntil, $username);
            $stmt->execute();
            $stmt->close();
            return;
        }

        $stmt = $conn->prepare(
            "UPDATE `{$table}`
             SET failed_attempts = ?, updated_at = NOW()
             WHERE username = ?"
        );
        if (!$stmt) {
            return;
        }
        $stmt->bind_param('is', $attempts, $username);
        $stmt->execute();
        $stmt->close();
    }

    private function recordDatabaseSuccessfulLogin(\mysqli $conn, string $table, string $username): void
    {
        $stmt = $conn->prepare(
            "UPDATE `{$table}`
             SET failed_attempts = 0, locked_until = NULL, last_login = NOW(), updated_at = NOW()
             WHERE username = ?"
        );
        if (!$stmt) {
            return;
        }
        $stmt->bind_param('s', $username);
        $stmt->execute();
        $stmt->close();
    }

    private function verifyTotpCode(string $secretBase32, string $code): bool
    {
        $code = preg_replace('/\D+/', '', $code) ?? '';
        if ($code === '' || strlen($code) !== 6) {
            return false;
        }

        $secret = $this->base32Decode($secretBase32);
        if ($secret === '') {
            return false;
        }

        $timeSlice = (int) floor(time() / 30);
        for ($i = -1; $i <= 1; $i++) {
            $generated = $this->generateTotp($secret, $timeSlice + $i);
            if (hash_equals($generated, $code)) {
                return true;
            }
        }

        return false;
    }

    private function generateTotp(string $secret, int $timeSlice): string
    {
        $time = pack('N*', 0) . pack('N*', $timeSlice);
        $hash = hash_hmac('sha1', $time, $secret, true);
        $offset = ord(substr($hash, -1)) & 0x0F;
        $binary = ((ord($hash[$offset]) & 0x7F) << 24)
            | ((ord($hash[$offset + 1]) & 0xFF) << 16)
            | ((ord($hash[$offset + 2]) & 0xFF) << 8)
            | (ord($hash[$offset + 3]) & 0xFF);

        $otp = $binary % 1000000;
        return str_pad((string) $otp, 6, '0', STR_PAD_LEFT);
    }

    private function base32Decode(string $input): string
    {
        $alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';
        $clean = strtoupper(preg_replace('/[^A-Z2-7]/', '', $input) ?? '');
        if ($clean === '') {
            return '';
        }

        $bits = '';
        $length = strlen($clean);
        for ($i = 0; $i < $length; $i++) {
            $val = strpos($alphabet, $clean[$i]);
            if ($val === false) {
                return '';
            }
            $bits .= str_pad(decbin($val), 5, '0', STR_PAD_LEFT);
        }

        $output = '';
        $chunks = str_split($bits, 8);
        foreach ($chunks as $chunk) {
            if (strlen($chunk) === 8) {
                $output .= chr(bindec($chunk));
            }
        }

        return $output;
    }
    private function verifyPbkdf2Password(string $password, string $storedHash): bool
    {
        $parts = explode('$', $storedHash);
        if (count($parts) !== 4 || $parts[0] !== 'pbkdf2_sha256') {
            return false;
        }

        $iterations = (int) $parts[1];
        $salt = base64_decode($parts[2], true);
        $hash = base64_decode($parts[3], true);

        if ($iterations < 100000 || $salt === false || $hash === false || $salt === '' || $hash === '') {
            return false;
        }

        $candidate = hash_pbkdf2('sha256', $password, $salt, $iterations, strlen($hash), true);
        return hash_equals($hash, $candidate);
    }

    private function createMailerFromEnv(): SmtpMailer
    {
        $smtpHost = (string) env('MAIL_HOST', 'smtp.strato.com');
        $smtpPort = (int) env('MAIL_PORT', 465);
        $smtpUser = (string) env('MAIL_USERNAME', '');
        $smtpPass = (string) env('MAIL_PASSWORD', '');
        $smtpEncryption = (string) env('MAIL_ENCRYPTION', 'ssl');

        return new SmtpMailer($smtpHost, $smtpPort, $smtpUser, $smtpPass, $smtpEncryption);
    }

    private function loginLockRemainingSeconds(): int
    {
        $attempts = $this->pruneFailedLoginAttempts();
        if (count($attempts) < self::LOGIN_MAX_ATTEMPTS) {
            return 0;
        }

        $oldestRelevant = $attempts[count($attempts) - self::LOGIN_MAX_ATTEMPTS] ?? null;
        if (!is_int($oldestRelevant)) {
            return 0;
        }

        $unlockAt = $oldestRelevant + self::LOGIN_WINDOW_SECONDS;
        return max(0, $unlockAt - time());
    }

    private function recordFailedLoginAttempt(): void
    {
        $attempts = $this->pruneFailedLoginAttempts();
        $attempts[] = time();
        $_SESSION['admin_login_attempts'] = $attempts;
    }

    private function clearFailedLoginAttempts(): void
    {
        $_SESSION['admin_login_attempts'] = [];
    }

    /**
     * @return array<int, int>
     */
    private function pruneFailedLoginAttempts(): array
    {
        $attempts = $_SESSION['admin_login_attempts'] ?? [];
        if (!is_array($attempts)) {
            $attempts = [];
        }

        $cutoff = time() - self::LOGIN_WINDOW_SECONDS;
        $attempts = array_values(array_filter(
            $attempts,
            static fn($timestamp): bool => is_int($timestamp) && $timestamp >= $cutoff
        ));

        $_SESSION['admin_login_attempts'] = $attempts;

        return $attempts;
    }

