    private function auditContext(array $context = []): array
    {
        $base = [
            'ip' => client_ip(),
            'user_agent' => substr((string) ($_SERVER['HTTP_USER_AGENT'] ?? 'unknown'), 0, 200),
            'admin_username' => (string) ($_SESSION['admin_username'] ?? 'unknown'),
        ];

        return array_merge($base, $context);
    }
    
